# --- Session Management ---

SESSION_PREFIX = "session:"
SESSION_EXPIRY = 3600  # 1 hour in seconds


class RedisSessionManager:
    """Manages user sessions stored in Redis with authentication."""

    def __init__(self, redis_conn, prefix=SESSION_PREFIX, expiry=SESSION_EXPIRY):
        self.redis = redis_conn
        self.prefix = prefix
        self.expiry = expiry

    def _get_key(self, session_id):
        return f"{self.prefix}{session_id}"

    def create_session(self, user_data):
        """Create a new session and return the session ID."""
        session_id = str(uuid4())
        key = self._get_key(session_id)
        serialized = json.dumps(user_data)
        self.redis.set(key, serialized, ex=self.expiry)
        return session_id

    def get_session(self, session_id):
        """Retrieve session data by session ID."""
        if not session_id:
            return None
        key = self._get_key(session_id)
        data = self.redis.get(key)
        if data:
            # Refresh TTL on access
            self.redis.expire(key, self.expiry)
            return json.loads(data)
        return None

    def update_session(self, session_id, user_data):
        """Update an existing session."""
        key = self._get_key(session_id)
        if self.redis.exists(key):
            serialized = json.dumps(user_data)
            self.redis.set(key, serialized, ex=self.expiry)
            return True
        return False

    def delete_session(self, session_id):
        """Delete a session."""
        key = self._get_key(session_id)
        return self.redis.delete(key) > 0

    def extend_session(self, session_id, additional_seconds=None):
        """Extend the TTL of a session."""
        key = self._get_key(session_id)
        ttl = additional_seconds or self.expiry
        return self.redis.expire(key, ttl)


session_manager = RedisSessionManager(redis_client)


# --- Caching Decorator ---

CACHE_PREFIX = "cache:"
DEFAULT_CACHE_TTL = 300  # 5 minutes


def cache_result(ttl=DEFAULT_CACHE_TTL, prefix=CACHE_PREFIX, key_builder=None):
    """
    Decorator to cache the result of expensive functions/queries in Redis.

    Args:
        ttl: Time-to-live in seconds for the cached result.
        prefix: Key prefix for cache entries.
        key_builder: Optional callable to build a custom cache key.
                     Receives (func, args, kwargs) and should return a string.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Build cache key
            if key_builder:
                cache_key_raw = key_builder(func, args, kwargs)
            else:
                # Default key: function name + hashed arguments
                key_data = {
                    'func': func.__qualname__,
                    'args': str(args),
                    'kwargs': str(sorted(kwargs.items())),
                }
                key_hash = hashlib.sha256(
                    json.dumps(key_data, sort_keys=True).encode()
                ).hexdigest()
                cache_key_raw = f"{func.__qualname__}:{key_hash}"

            cache_key = f"{prefix}{cache_key_raw}"

            # Try to get from cache
            try:
                cached = redis_client.get(cache_key)
                if cached is not None:
                    result = json.loads(cached)
                    return result
            except Exception as e:
                # If cache read fails, proceed without cache
                app.logger.warning(f"Cache read error for key {cache_key}: {e}")

            # Execute the function
            result = func(*args, **kwargs)

            # Store in cache
            try:
                serialized = json.dumps(result)
                redis_client.set(cache_key, serialized, ex=ttl)
            except Exception as e:
                app.logger.warning(f"Cache write error for key {cache_key}: {e}")

            return result
        
        # Attach cache invalidation helper
        def invalidate(*args, **kwargs):
            """Invalidate the cache for specific arguments."""
            if key_builder:
                cache_key_raw = key_builder(func, args, kwargs)
            else:
                key_data = {
                    'func': func.__qualname__,
                    'args': str(args),
                    'kwargs': str(sorted(kwargs.items())),
                }
                key_hash = hashlib.sha256(
                    json.dumps(key_data, sort_keys=True).encode()
                ).hexdigest()
                cache_key_raw = f"{func.__qualname__}:{key_hash}"
            cache_key = f"{prefix}{cache_key_raw}"
            redis_client.delete(cache_key)

        def invalidate_all():
            """Invalidate all cache entries for this function."""
            pattern = f"{prefix}{func.__qualname__}:*"
            cursor = 0
            while True:
                cursor, keys = redis_client.scan(cursor, match=pattern, count=100)
                if keys:
                    redis_client.delete(*keys)
                if cursor == 0:
                    break

        wrapper.invalidate = invalidate
        wrapper.invalidate_all = invalidate_all
        return wrapper
    return decorator


