# --- Rate Limiting Helper ---

RATE_LIMIT_PREFIX = "ratelimit:"


def check_rate_limit(identifier, max_requests=100, window_seconds=60):
    """Simple sliding window rate limiter using Redis."""
    key = f"{RATE_LIMIT_PREFIX}{identifier}"
    current = redis_client.get(key)
    if current is None:
        pipe = redis_client.pipeline()
        pipe.set(key, 1, ex=window_seconds)
        pipe.execute()
        return True, max_requests - 1
    elif int(current) < max_requests:
        redis_client.incr(key)
        remaining = max_requests - int(current) - 1
        return True, remaining
    else:
        ttl = redis_client.ttl(key)
        return False, 0


# --- Middleware ---

@app.before_request
def rate_limit_middleware():
    """Apply rate limiting per IP address."""
    client_ip = request.remote_addr
    allowed, remaining = check_rate_limit(client_ip, max_requests=200, window_seconds=60)
    if not allowed:
        return jsonify({"error": "Rate limit exceeded. Try again later."}), 429


