@app.route('/health', methods=['GET'])
def health():
    """Health check endpoint that verifies Redis connectivity."""
    redis_healthy = False
    redis_info = {}

    try:
        redis_client.ping()
        redis_healthy = True
        info = redis_client.info(section='memory')
        redis_info = {
            "connected": True,
            "used_memory_human": info.get("used_memory_human", "unknown"),
            "connected_clients": redis_client.info(section='clients').get("connected_clients", "unknown"),
        }
    except Exception as e:
        redis_info = {
            "connected": False,
            "error": str(e),
        }

    status = "healthy" if redis_healthy else "degraded"
    status_code = 200 if redis_healthy else 503

    return jsonify({
        "status": status,
        "redis": redis_info,
        "timestamp": time.time(),
    }), status_code


